                        <span class="badge" onclick="event.stopPropagation();app.openScoreAdjustmentModal('prospect',${e.id})" style="background:var(--primary);color:#fff;cursor:pointer;user-select:none;" title="Click to adjust score">\u2B50 ${e.score||0} pts (${ne(e.score||0)}) <i class="fas fa-pen" style="font-size:9px;opacity:.8;margin-left:2px;"></i></span>
